package visitorDemoExercises.listFWVisitorExercises.model.visitors;

import provided.listFW.IListAlgo;
import provided.listFW.MTList;
import provided.listFW.NEList;

/**
 * Returns the sum of a list of integers using reverse accumulation starting from nth.
 * The input parameter is not used ("nu").
 */
public class FromNthAlgo implements IListAlgo {
	private int parseIndex(Object raw) {
		return raw instanceof String ? Integer.parseInt((String) raw) : ((Number) raw).intValue();
	}

	/**
	 * Returns zero always.
	 */
	public Object emptyCase(MTList host, Object... nu) {
		return 0;
	}

	/**
	 * Returns first plus the sum of the rest of the list.
	 */
	public Object nonEmptyCase(NEList host, Object... params) {
		int n = parseIndex(params[0]);
		if (n <= 1) {
			return (Integer) host.getFirst() + (Integer) host.getRest().execute(this, 1);
		}
		return host.getRest().execute(this, n - 1);
	}

}

package visitorDemoExercises.listFWVisitorExercises.model.visitors;

import provided.listFW.IListAlgo;
import provided.listFW.MTList;
import provided.listFW.NEList;

/**
 * Returns the boolean value if a param is in a list of integers using reverse accumulation.
 * The input parameter is not used ("nu").
 */
public class SearchRevAlgo implements IListAlgo {
	/**
	 * Returns zero always.
	 */
	public Object emptyCase(MTList host, Object... nu) {
		return false;
	}

	/**
	 * Returns first plus the result of the rest of the list.
	 */
	public Object nonEmptyCase(NEList host, Object... param) {
		int target = Integer.parseInt((String) param[0]);
		return ((Integer) host.getFirst() == target) || (Boolean) host.getRest().execute(this, param);
	}

}

package visitorDemoExercises.listFWVisitorExercises.model.visitors;

import provided.listFW.IListAlgo;
import provided.listFW.MTList;
import provided.listFW.NEList;


/**
 *  Returns the largest of a list of integers using forward accumulation.
 *  The input parameter is not used ("nu").
 * @author Son Nguyen and Charlie Lockyer
 *
 */
public class LargestFwdAlgo implements IListAlgo {

	@Override
	/**
	 * The base case value is Min_Value,
	 */
	public Object emptyCase(MTList host, Object... nu) {
		return Integer.MIN_VALUE;
	}

	@Override
	/**
	 * Pass the first value to the rest of the list, using a helper visitor, to be accumulated.
	 */
	public Object nonEmptyCase(NEList host, Object... nu) {
		return Math.max((Integer) host.getFirst(), (Integer) host.getRest().execute(this));
	}

}

