package hw05.model.interactStrategies;

import java.awt.Color;
import java.awt.Point;
import java.util.concurrent.ThreadLocalRandom;

import hw05.model.Ball;
import hw05.model.IBall;
import hw05.model.IBallAlgo;
import hw05.model.IBallCmd;
import hw05.model.updateStrategies.MultiStrategy;
import provided.utils.dispatcher.IDispatcher;

/**
 * The interact strategy that generates a new ball with the average radius and color of the two balls that interacted
 *
 */
public class ReproduceStrategy implements IInteractStrategy {

	/**
	 * Generates a new ball with the average radius and color of the two balls that interacted
	 * NOTE TO INSTRUCTORS: THIS IS BROKEN, DO NOT COUNT AS ONE OF OUR STRATEGIES OR GRADE
	 */
	public IBallCmd interactWith(IBall context, IBall target, IDispatcher<IBallCmd> disp) {
		return (ball, d) -> {
			if (System.identityHashCode(context) >= System.identityHashCode(target)) {
				return;
			}

			Point contextLoc = context.getLocation();
			Point targetLoc = target.getLocation();
			Point childLocation = new Point((contextLoc.x + targetLoc.x) / 2, (contextLoc.y + targetLoc.y) / 2);
			Point childVelocity = new Point(ThreadLocalRandom.current().nextInt(-10, 11),
					ThreadLocalRandom.current().nextInt(-10, 11));
			if (childVelocity.x == 0 && childVelocity.y == 0) {
				childVelocity.x = 1;
			}

			Color contextColor = context.getColor();
			Color targetColor = target.getColor();
			Color childColor = new Color((contextColor.getRed() + targetColor.getRed()) / 2,
					(contextColor.getGreen() + targetColor.getGreen()) / 2,
					(contextColor.getBlue() + targetColor.getBlue()) / 2);
			int childRadius = (context.getRadius() + target.getRadius()) / 2;

			IBallAlgo childAlgo = new IBallAlgo() {
				@Override
				public void caseDefault(IBall host) {
					host.setUpdateStrategy(new MultiStrategy(context.getUpdateStrategy(), target.getUpdateStrategy()));
					host.setInteractStrategy(context.getInteractStrategy());
				}
			};

			d.addObserver(new Ball(childLocation, childVelocity, childColor, childRadius, context.getDimension(),
					context.getCanvas(), childAlgo));
		};
	}

	public void init(IBall context) {
		// TODO Auto-generated method stub

	}

}

package hw05.model.interactStrategies;

import java.awt.Point;
import java.awt.geom.Point2D;

import hw05.model.IBall;
import hw05.model.IBallCmd;
import provided.utils.dispatcher.IDispatcher;

/**
 * @author cindy
 * Elastic Collision without decomposition
 *
 */
public class CollideStrategy implements  IInteractStrategy {

	@Override
	public IBallCmd interactWith(IBall source, IBall target, IDispatcher<IBallCmd> disp) {
		Point sourceLoc = source.getLocation();
		Point targetLoc = target.getLocation();
		double distance = sourceLoc.distance(targetLoc);
		double minSeparation = source.getRadius() + target.getRadius();
		if (distance >= minSeparation || distance == 0.0) {
			return (context, d) -> {};
		}

		double sourceMass = source.getRadius() * source.getRadius();
		double targetMass = target.getRadius() * target.getRadius();
		Point2D.Double normalVec = calcUnitVec(sourceLoc, targetLoc, distance);
		Point2D.Double impulseVec = impulse(normalVec, source.getVelocity(), target.getVelocity(),
				reducedMass(sourceMass, targetMass));
		Point nudgeVec = calcNudgeVec(normalVec, minSeparation, distance);

		return (context, d) -> {
			updateVelocity(source, sourceMass, impulseVec);
			Point displaced = new Point(source.getLocation());
			displaced.translate(-nudgeVec.x, -nudgeVec.y);
			source.setLocation(displaced);
		};
	}

	/**
	 * Returns the reduced mass of the two balls (m1*m2)/(m1+m2) Gives correct
	 * result if one of the balls has infinite mass.
	 * 
	 * @param mSource
	 *            Mass of the source ball
	 * @param mTarget
	 *            Mass of the target ball
	 * @return The reduced mass of the two balls
	 */
	protected double reducedMass(double mSource, double mTarget) {
		if (Double.isInfinite(mSource) && Double.isInfinite(mTarget)) {
			return Double.POSITIVE_INFINITY;
		}
		if (Double.isInfinite(mSource)) {
			return mTarget;
		}
		if (Double.isInfinite(mTarget)) {
			return mSource;
		}
		double totalMass = mSource + mTarget;
		return totalMass == 0.0 ? 0.0 : (mSource * mTarget) / totalMass;
	}

	/**
	 * Calculate the unit vector (normalized vector) from the location of the source ball to the location of the target ball.
	 * @param lSource Location of the source ball
	 * @param lTarget Location of the target ball
	 * @param distance Distance from the source ball to the target ball
	 * @return A double-precision vector (point)
	 */
	Point2D.Double calcUnitVec(Point lSource, Point lTarget, double distance) {
		return new Point2D.Double((lTarget.x - lSource.x) / distance, (lTarget.y - lSource.y) / distance);
	}		

	/**
	 * Calculates the impulse (change in momentum) of the collision in the
	 * direction from the source to the target This method calculates the
	 * impulse on the source ball. The impulse on the target ball is the
	 * negative of the result. The change in velocity of the source ball is the
	 * impulse divided by the source's mass The change in velocity of the target
	 * ball is the negative of the impulse divided by the target's mass
	 * 
	 * @param normalVec 
	 *            The unit vector (normalized vector) from the location of the source ball to the location of the target ball.
	 * @param vSource
	 *            Velocity of the source ball
	 * @param vTarget
	 *            Velocity of the target ball
	 * @param reducedMass
	 *            Reduced mass of the two balls
	 * @return The value of the collision's impulse
	 */
	protected Point2D.Double impulse(Point2D.Double normalVec, Point vSource, Point vTarget, double reducedMass) {
		double relativeNormalVelocity = (vSource.x - vTarget.x) * normalVec.x + (vSource.y - vTarget.y) * normalVec.y;
		if (relativeNormalVelocity <= 0.0) {
			return new Point2D.Double(0.0, 0.0);
		}
		double scale = -2.0 * reducedMass * relativeNormalVelocity;
		return new Point2D.Double(scale * normalVec.x, scale * normalVec.y);
	}


	/**
	 * The multiplicative factor to increase the separation distance to insure that the two balls
	 * are beyond collision distance
	 */
	private static final double NudgeFactor = 1.1;

	/**
	 * Calculate the vector to add to the source ball's location to "nudge" it out of the way of the target ball.
	 * @param normalVec  The unit vector (normalized vector) from the location of the source ball to the location of the target ball.
	 * @param minSeparation The minimum allowed non-colliding separation between the centers of the balls = maximum allowed colliding separation.
	 * @param distance The actual distance between the centers of the balls.
	 * @return A Point object which is the amount to "nudge" the source ball away from the target ball.
	 */
	Point calcNudgeVec(Point2D.Double normalVec, double minSeparation, double distance) {
		double nudgeMagnitude = ((minSeparation - distance) * NudgeFactor) / 2.0;
		return new Point((int) Math.round(normalVec.x * nudgeMagnitude), (int) Math.round(normalVec.y * nudgeMagnitude));
	}

	/**
	 * Updates the velocity of a ball, given an impulse vector. The change in velocity is the 
	 * impulse divided by the ball's mass. 
	 * 
	 * @param aBall
	 *            The ball whose velocity needs to be modified by the impulse
	 * @param mass 
	 *            The "mass" of the ball
	 * @param impulseVec 
	 *            The impulse vector for the ball
	 */
	protected void updateVelocity(IBall aBall, double mass, Point2D.Double impulseVec) {
		if (mass == 0.0) {
			return;
		}
		Point velocity = aBall.getVelocity();
		int newX = (int) Math.round(velocity.x + impulseVec.x / mass);
		int newY = (int) Math.round(velocity.y + impulseVec.y / mass);
		aBall.setVelocity(new Point(newX, newY));
	}

	@Override
	public void init(IBall context) {
		// TODO Auto-generated method stub

	}

	// Utilities for calculating reduced mass, unit vector, impuylse and nudge vector elided.

}

package hw05.model.interactStrategies;

import java.awt.Point;
import hw05.model.IBall;
import hw05.model.IBallCmd;
import provided.utils.dispatcher.IDispatcher;

/**
 * A strategy in which balls that interact are attracted to one another in a way that appears magnetic
 * @author charlielockyer
 *
 */
public class AttractStrategy implements  IInteractStrategy {

	/**
	 * Nudge factor
	 */
	static final double attractNudge = 0.0025;

	public IBallCmd interactWith(IBall source, IBall target, IDispatcher<IBallCmd> disp) {
		return (context, d) -> {
			Point velocity = source.getVelocity();
			Point sourceLoc = source.getLocation();
			Point targetLoc = target.getLocation();
			int deltaX = (int) ((targetLoc.x - sourceLoc.x) * attractNudge);
			int deltaY = (int) ((targetLoc.y - sourceLoc.y) * attractNudge);
			source.setVelocity(new Point(velocity.x + deltaX, velocity.y + deltaY));
		};
	}

	public void init(IBall context) {
		// TODO Auto-generated method stub

	}

	// Utilities for calculating reduced mass, unit vector, impuylse and nudge vector elided.

}

package comp310.tests.hw05;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.awt.Color;
import java.awt.Point;

import org.junit.jupiter.api.Test;

import hw05.model.Ball;
import hw05.model.IBall;
import hw05.model.IBallAlgo;
import hw05.model.IBallCmd;
import hw05.model.interactStrategies.AttractStrategy;
import hw05.model.interactStrategies.CollideStrategy;
import hw05.model.interactStrategies.FreezeStrategy;
import hw05.model.updateStrategies.CollideCriteriaStrategy;
import hw05.model.updateStrategies.SameColorCriteriaStrategy;
import provided.utils.displayModel.IDimension;
import provided.utils.dispatcher.impl.SequentialDispatcher;

class HW05AgentTest {

    private IDimension mockDim(int w, int h) {
        return new IDimension() {
            public int getWidth() { return w; }
            public int getHeight() { return h; }
        };
    }

    private IBallAlgo noOpAlgo() {
        return new IBallAlgo() {
            @Override
            public void caseDefault(IBall host) {
            }
        };
    }

    private Ball makeBall(Point location, Point velocity, Color color, int radius) {
        return new Ball(location, velocity, color, radius, mockDim(800, 600), null, noOpAlgo());
    }

    @Test
    void collideCommandSeparatesOverlappingBalls() {
        Ball source = makeBall(new Point(100, 100), new Point(3, 0), Color.RED, 20);
        Ball target = makeBall(new Point(130, 100), new Point(0, 0), Color.BLUE, 20);

        IBallCmd cmd = new CollideStrategy().interactWith(source, target, new SequentialDispatcher<>());
        cmd.apply(source, new SequentialDispatcher<>());

        assertTrue(source.getLocation().x < 100, "Collision command should nudge the source away from the target");
    }

    @Test
    void collideCriteriaAppliesEachBallCommandOncePerPair() {
        Ball source = makeBall(new Point(100, 100), new Point(4, 2), Color.RED, 20);
        Ball target = makeBall(new Point(125, 100), new Point(-3, -1), Color.BLUE, 20);
        source.setInteractStrategy(new FreezeStrategy());
        target.setInteractStrategy(new AttractStrategy());

        SequentialDispatcher<IBallCmd> dispatcher = new SequentialDispatcher<>();
        dispatcher.addObserver(source);
        dispatcher.addObserver(target);

        new CollideCriteriaStrategy().updateState(source, dispatcher);

        assertEquals(new Point(0, 0), source.getVelocity(), "Source command should freeze the source ball");
        assertTrue(target.getVelocity().x < -3 || target.getVelocity().y != -1,
                "Target command should apply its own interaction response");
    }

    @Test
    void sameColorCriteriaUsesThresholdForNearMatches() {
        Ball source = makeBall(new Point(100, 100), new Point(5, 0), new Color(100, 100, 100), 10);
        Ball target = makeBall(new Point(200, 200), new Point(-2, 1), new Color(120, 120, 120), 10);
        source.setInteractStrategy(new FreezeStrategy());
        target.setInteractStrategy(new FreezeStrategy());

        SequentialDispatcher<IBallCmd> dispatcher = new SequentialDispatcher<>();
        dispatcher.addObserver(source);
        dispatcher.addObserver(target);

        new SameColorCriteriaStrategy().updateState(source, dispatcher);

        assertEquals(new Point(0, 0), source.getVelocity(), "Colors within the threshold should trigger interaction");
    }
}

