+package comp310.tests.hw06;
+
+import static org.junit.jupiter.api.Assertions.assertEquals;
+import static org.junit.jupiter.api.Assertions.assertFalse;
+import static org.junit.jupiter.api.Assertions.assertTrue;
+
+import java.awt.Color;
+import java.awt.Component;
+import java.awt.Point;
+
+import javax.swing.JPanel;
+
+import org.junit.jupiter.api.Test;
+
+import hw06.model.BallHosts.DefaultBall;
+import hw06.model.BallHosts.DynamicBall;
+import hw06.model.BallHosts.FollowerBall;
+import hw06.model.BallHosts.IBall;
+import hw06.model.BallVisitors.ABallAlgoCmd;
+import hw06.model.BallVisitors.BallAlgo;
+import hw06.model.BallVisitors.IBallAlgo;
+import hw06.model.BallVisitors.OneTypeBallAlgo;
+import hw06.model.BallVisitors.SameTypeBallAlgo;
+import provided.ballworld.extVisitors.IBallHostID;
+import provided.listFW.IList;
+import provided.listFW.MTList;
+import provided.listFW.NEList;
+import visitorDemoExercises.listFWVisitorExercises.model.visitors.RemoveSmallestRevAlgo;
+
+class AgentCoverageTest {
+
+	private Component mockContainer() {
+		JPanel panel = new JPanel();
+		panel.setSize(800, 600);
+		return panel;
+	}
+
+	private IBallAlgo<Void, Void> noOpInstallAlgo() {
+		return new BallAlgo<>(new ABallAlgoCmd<Void, Void>() {
+			private static final long serialVersionUID = 1L;
+
+			@Override
+			public Void apply(IBallHostID index, IBall host, Void... params) {
+				return null;
+			}
+		});
+	}
+
+	private IList list(Integer... vals) {
+		IList result = MTList.Singleton;
+		for (int i = vals.length - 1; i >= 0; i--) {
+			result = new NEList(vals[i], result);
+		}
+		return result;
+	}
+
+	@Test
+	void testOneTypeBallAlgoOnlyTargetsChosenType() {
+		OneTypeBallAlgo<Integer> algo = new OneTypeBallAlgo<>("All", false);
+		algo.setType(FollowerBall.ID);
+
+		Component container = mockContainer();
+		IBall follower = new FollowerBall(new Point(0, 0), 5, new Point(1, 1), Color.BLUE, container, noOpInstallAlgo());
+		IBall defaultBall = new DefaultBall(new Point(0, 0), 5, new Point(1, 1), Color.RED, container, noOpInstallAlgo());
+
+		assertEquals(1, follower.execute(algo, ball -> 1));
+		assertEquals(null, defaultBall.execute(algo, ball -> 1));
+	}
+
+	@Test
+	void testSameTypeBallAlgoUsesDynamicHostIds() {
+		Component container = mockContainer();
+		DynamicBall dynamicBall = new DynamicBall(new Point(0, 0), 5, new Point(1, 1), Color.BLACK, container, noOpInstallAlgo());
+		DefaultBall defaultBall = new DefaultBall(new Point(0, 0), 5, new Point(1, 1), Color.RED, container, noOpInstallAlgo());
+		FollowerBall followerBall = new FollowerBall(new Point(0, 0), 5, new Point(1, 1), Color.BLUE, container, noOpInstallAlgo());
+
+		dynamicBall.setHostID(DefaultBall.ID);
+		assertTrue(dynamicBall.execute(SameTypeBallAlgo.Singleton, defaultBall));
+
+		dynamicBall.setHostID(FollowerBall.ID);
+		assertFalse(dynamicBall.execute(SameTypeBallAlgo.Singleton, defaultBall));
+		assertTrue(dynamicBall.execute(SameTypeBallAlgo.Singleton, followerBall));
+	}
+
+	@Test
+	void testRemoveSmallestRevAlgoRemovesFirstDuplicateMinimum() {
+		IList result = (IList) list(3, 1, 4, 1, 5).execute(new RemoveSmallestRevAlgo());
+
+		assertEquals("[3, 4, 1, 5]", result.toString());
+	}
+}
